import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as d,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"الوسم التلقائي","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Other/auto-tagging.md","filePath":"ar-SA/Other/auto-tagging.md","lastUpdated":1781962217000}'),o={name:"ar-SA/Other/auto-tagging.md"};function n(l,a,p,c,r,g){return d(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="الوسم-التلقائي" tabindex="-1">الوسم التلقائي <a class="header-anchor" href="#الوسم-التلقائي" aria-label="Permalink to &quot;الوسم التلقائي&quot;">​</a></h1><p>يُضبط Auto Tagging من:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>ينشئ النظام وسوم الصور تلقائيًا، وهي مفيدة للبحث، وتصفية random image، وتصفية public gallery، والتحكم في الوصول حسب التقييم العمري.</p><h2 id="ماذا-يستطيع-auto-tagging-فعله؟" tabindex="-1">ماذا يستطيع Auto Tagging فعله؟ <a class="header-anchor" href="#ماذا-يستطيع-auto-tagging-فعله؟" aria-label="Permalink to &quot;ماذا يستطيع Auto Tagging فعله؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الميزة</th><th>الوصف</th></tr></thead><tbody><tr><td>إنشاء content tags</td><td>يضيف وسومًا للأشخاص والمشاهد والعناصر والأسلوب الفني والمحتوى البصري المشابه.</td></tr><tr><td>إنشاء character tags</td><td>مفيد لصور الأنمي والرسوم.</td></tr><tr><td>إضافة orientation tags</td><td>يضيف <code>landscape</code> أو <code>portrait</code> أو <code>square</code>.</td></tr><tr><td>إضافة image rating</td><td>يحفظ نتائج <code>G/S/Q/E</code> للمحتوى العام أو الحساس أو المشكوك فيه أو الصريح.</td></tr><tr><td>Auto-tag on upload</td><td>تدخل الصور الجديدة مسار الوسم تلقائيًا.</td></tr><tr><td>Batch tagging</td><td>يضيف وسومًا للصور القديمة في كل المجلدات أو المجلدات المحددة.</td></tr></tbody></table><h2 id="ما-الذي-تحتاجه-أولًا؟" tabindex="-1">ما الذي تحتاجه أولًا؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-أولًا؟" aria-label="Permalink to &quot;ما الذي تحتاجه أولًا؟&quot;">​</a></h2><p>جهّز رابط Hugging Face Space واحدًا على الأقل يمكن الوصول إليه.</p><p>الطريقة الموصى بها هي نسخ Space الخاص بـ SmilingWolf باسم <code>wd-tagger</code> إلى حساب Hugging Face الخاص بك:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>يمكنك استخدام الـ Space العام مؤقتًا للتجربة، لكنه مشترك بين كثير من المستخدمين وقد يتأخر أو يدخل في طابور أو يتوقف مؤقتًا. النسخة الموجودة في حسابك عادة أكثر ثباتًا للاستخدام اليومي.</p><h2 id="نسخ-space-الخاص-بـ-smilingwolf" tabindex="-1">نسخ Space الخاص بـ SmilingWolf <a class="header-anchor" href="#نسخ-space-الخاص-بـ-smilingwolf" aria-label="Permalink to &quot;نسخ Space الخاص بـ SmilingWolf&quot;">​</a></h2><ol><li>سجّل الدخول إلى Hugging Face.</li><li>افتح <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+t+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>اضغط قائمة النقاط الثلاث في الزاوية العلوية اليمنى.</li><li>اختر <code>Duplicate this Space</code>.</li><li>اترك الاسم الافتراضي أو اختر اسمًا مثل <code>wd-tagger</code>.</li><li>اجعل visibility على <code>Public</code>. هذا يجعل استدعاء ImgBed أسهل.</li><li>ابدأ بالعتاد المجاني الافتراضي. قم بالترقية فقط إذا لاحظت طوابير واضحة.</li><li>أنشئ Space وانتظر اكتمال البناء.</li></ol><p>بعد اكتمال البناء، افتح صفحة Space الخاصة بك. غالبًا يكون الرابط بالشكل:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>انسخ الرابط من المتصفح والصقه في <code>Space URLs</code> داخل ImgBed.</p><h2 id="إدخال-عدة-space-urls" tabindex="-1">إدخال عدة Space URLs <a class="header-anchor" href="#إدخال-عدة-space-urls" aria-label="Permalink to &quot;إدخال عدة Space URLs&quot;">​</a></h2><p>أدخل رابط Space واحدًا في كل سطر.</p><table tabindex="0"><thead><tr><th>القيمة</th><th>الوصف</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>Space العام لـ SmilingWolf. مناسب للتجربة المؤقتة.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>رابط صفحة Space منسوخ.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Space الذي نسخته إلى حسابك.</td></tr></tbody></table><p>يمكن إدخال عدة روابط. يستخدم ImgBed عدة Spaces معًا وقد يحسن ذلك السرعة.</p><p>إذا تعطل Space مؤقتًا، يمكن للآخرين متابعة المعالجة.</p><h2 id="الإعدادات" tabindex="-1">الإعدادات <a class="header-anchor" href="#الإعدادات" aria-label="Permalink to &quot;الإعدادات&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الخيار</th><th>التوصية</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>أدخل روابط Space التي جهزتها. استخدم واحدًا على الأقل.</td></tr><tr><td>Target folder</td><td>اتركه فارغًا لكل المجلدات. اختر مجلدًا فقط إذا أردت معالجة مجلد محدد.</td></tr><tr><td>Recognition model</td><td>اترك <code>wd-swinv2-tagger-v3</code> افتراضيًا.</td></tr><tr><td>General tag threshold</td><td>القيمة الافتراضية مناسبة لمعظم الصور. القيمة الأقل تنتج وسومًا أكثر، والأعلى تنتج وسومًا أقل.</td></tr><tr><td>Character tag threshold</td><td>القيمة الافتراضية محافظة وتقلل أخطاء character tags.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>اتركه مغلقًا في البداية. فعّله إذا أردت أن يقرر النموذج عدد الوسوم تلقائيًا.</td></tr><tr><td>Auto-tag on upload</td><td>فعّله إذا كانت الصور الجديدة يجب أن تُوسم تلقائيًا.</td></tr><tr><td>Start tagging</td><td>يشغّل وسمًا جماعيًا يدويًا للصور القديمة.</td></tr></tbody></table><h2 id="قيم-بداية-مقترحة" tabindex="-1">قيم بداية مقترحة <a class="header-anchor" href="#قيم-بداية-مقترحة" aria-label="Permalink to &quot;قيم بداية مقترحة&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الخيار</th><th>القيمة المقترحة</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>مغلق في البداية</td></tr><tr><td>Auto-tag on upload</td><td>فعّله عند الحاجة</td></tr></tbody></table><p>إذا كانت الوسوم كثيرة، ارفع general threshold قليلًا. إذا كانت قليلة، اخفضه قليلًا.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li>املأ <code>Space URLs</code>.</li><li>اختر target folder.</li><li>اضغط start tagging.</li><li>انتظر اكتمال التقدم.</li></ol><p>إذا كان target folder فارغًا، يعالج ImgBed كل المجلدات.</p><p>Batch tagging مناسب للصور القديمة. للصور الجديدة فعّل auto-tag on upload حتى لا تحتاج إلى تشغيله يدويًا كل مرة.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>بعد تفعيله، تستدعي الصور الجديدة روابط <code>Space URLs</code> المضبوطة تلقائيًا.</p><p>هذا مناسب للاستخدام المستمر.</p><p>إذا كان Space في طابور، يمكن أن يكتمل الرفع أولًا وتستمر عملية الوسم بعده.</p><h2 id="أي-الصور-تُعالج؟" tabindex="-1">أي الصور تُعالج؟ <a class="header-anchor" href="#أي-الصور-تُعالج؟" aria-label="Permalink to &quot;أي الصور تُعالج؟&quot;">​</a></h2><p>يعالج Auto tagging ملفات الصور أساسًا.</p><p>تُتجاوز الصور التي تملك بالفعل tags و orientation و rating و width و height كاملة لتجنب استدعاءات Space غير الضرورية.</p><p>يحاول ImgBed ملء المعلومات الناقصة فقط متى أمكن. مثلًا، إذا كان orientation فقط مفقودًا، يحاول إضافته دون تشغيل مسار وسوم المحتوى كاملًا.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="لماذا-أنسخ-space-خاصًا-بي؟" tabindex="-1">لماذا أنسخ Space خاصًا بي؟ <a class="header-anchor" href="#لماذا-أنسخ-space-خاصًا-بي؟" aria-label="Permalink to &quot;لماذا أنسخ Space خاصًا بي؟&quot;">​</a></h3><p>Spaces العامة مشتركة بين كثير من المستخدمين. النسخة الخاصة بك يستخدمها موقعك غالبًا، لذلك تكون أسرع وأكثر موثوقية.</p><h3 id="space-يستغرق-وقتًا-في-البدء" tabindex="-1">Space يستغرق وقتًا في البدء <a class="header-anchor" href="#space-يستغرق-وقتًا-في-البدء" aria-label="Permalink to &quot;Space يستغرق وقتًا في البدء&quot;">​</a></h3><p>بعد الإنشاء الأول أو فترة خمول طويلة قد يحتاج Space إلى وقت للبدء.</p><p>افتح صفحة Space أولًا. بعد أن يستطيع التعرف على صورة بشكل طبيعي، ارجع إلى ImgBed وابدأ الوسم.</p><h3 id="كيف-أنسخ-space-url؟" tabindex="-1">كيف أنسخ Space URL؟ <a class="header-anchor" href="#كيف-أنسخ-space-url؟" aria-label="Permalink to &quot;كيف أنسخ Space URL؟&quot;">​</a></h3><p>افتح صفحة Hugging Face Space وانسخ عنوان المتصفح.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="هل-يمكن-إضافة-عدة-spaces؟" tabindex="-1">هل يمكن إضافة عدة Spaces؟ <a class="header-anchor" href="#هل-يمكن-إضافة-عدة-spaces؟" aria-label="Permalink to &quot;هل يمكن إضافة عدة Spaces؟&quot;">​</a></h3><p>نعم. أدخل رابط Space واحدًا في كل سطر.</p><p>عدة Spaces تعالج الصور معًا وهي مفيدة إذا كان لديك عدد كبير من الصور.</p><h3 id="لماذا-الوسوم-بالإنجليزية؟" tabindex="-1">لماذا الوسوم بالإنجليزية؟ <a class="header-anchor" href="#لماذا-الوسوم-بالإنجليزية؟" aria-label="Permalink to &quot;لماذا الوسوم بالإنجليزية؟&quot;">​</a></h3><p>نماذج SmilingWolf تُخرج وسومًا إنجليزية. هذا متوقع.</p><p>تستخدم الوسوم أساسًا للبحث والتصفية و random image API وفلاتر public gallery.</p><h3 id="ما-فائدة-rating-tags؟" tabindex="-1">ما فائدة rating tags؟ <a class="header-anchor" href="#ما-فائدة-rating-tags؟" aria-label="Permalink to &quot;ما فائدة rating tags؟&quot;">​</a></h3><p>تعمل نتائج rating مع access mode في Security Settings.</p><p>مثلًا، عند تقييد وصول الزوار حسب التقييم العمري، تُفلتر ميزات التصفح العام و random image الصور حسب تلك القواعد.</p><h2 id="المسار-السريع" tabindex="-1">المسار السريع <a class="header-anchor" href="#المسار-السريع" aria-label="Permalink to &quot;المسار السريع&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>سجّل الدخول إلى Hugging Face</span></span>
<span class="line"><span>-&gt; افتح SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; انتظر بناء Space</span></span>
<span class="line"><span>-&gt; انسخ Space URL</span></span>
<span class="line"><span>-&gt; املأ Space URLs في ImgBed</span></span>
<span class="line"><span>-&gt; اختر النموذج وال thresholds</span></span>
<span class="line"><span>-&gt; ابدأ tagging أو فعّل auto-tag on upload</span></span></code></pre></div>`,60)])])}const m=e(o,[["render",n]]);export{b as __pageData,m as default};
